const today = new Date().toISOString().slice(5, 10); // MM-DD
const FESTIVALS = { '01-14': { name: 'Pongal', code: 'PONGAL15' }, '04-14': { name: 'Vishu', code: 'VISHU20' }, '08-26': { name: 'Onam', code: 'ONAM25' }, '12-25': { name: 'Christmas', code: 'XMAS20' } };
const hit = FESTIVALS[today];
return hit ? [{ json: { festival: hit.name, offer_code: hit.code } }] : [];
